I still have to create proper tests (with checking) and investigate regression fallout.  However both the test from #6659 and the one below now successfully build.

```
virtual class funcA_c #(parameter p_width=4);
   static function logic[p_width-1:0] funcA(
      input logic[p_width-1:0] inb
   );
      funcA = 'h5;
   endfunction
endclass

virtual class funcB_c #(parameter p_width=4);
   static function logic[p_width-1:0] funcB(
      input logic[p_width-1:0] inb
   );
      funcB = funcA_c#(.p_width(p_width))::funcA(inb);
   endfunction
endclass

module modA #(parameter int unsigned p_width = 7)(
   input logic [p_width-1:0] inb_i
);
   logic [p_width-1:0] sig_b;
   assign sig_b = funcB_c#(.p_width(p_width))::funcB(inb_i);
endmodule

module the_top();
   localparam int Size = 3;

   logic [Size-1:0] sig_a;

   modA #(.p_width(Size)) modA(
      .inb_i(sig_a)
   );

   initial begin
      $write("*-* All Finished *-*\n");
      $finish;
   end
endmodule
